package be.schaubroeck.lpb.rkm.rekenmotor.rsz;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmTijdperk;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplStatuutDmfappl;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetal;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuut;
import be.schaubroeck.lpb.tools.rsz.dmfa.CategorieKengetalStatuutDmfa;
import be.schaubroeck.lpb.tools.rsz.dmfappl.CategorieKengetalStatuutDmfappl;

public final class CategorieKengetalStatuutFactory {
    private CategorieKengetalStatuutFactory() {
    }

    public static CategorieKengetalStatuut getCategorieKengetalStatuut(RekenTijd rekenTijd, CategorieKengetal categorieKengetal, DmfapplStatuutDmfappl statuutDmfappl) {
        if (rekenTijd.isDmfa()) {
            return new CategorieKengetalStatuutDmfa(categorieKengetal, statuutDmfappl);
        } else {
            return new CategorieKengetalStatuutDmfappl(categorieKengetal, statuutDmfappl);
        }
    }

    public static CategorieKengetalStatuut getCategorieKengetalStatuut(RkmTijdperk tijdperk, CategorieKengetal categorieKengetal, DmfapplStatuutDmfappl statuutDmfappl) {
        if (tijdperk == RkmTijdperk.DMFA) {
            return new CategorieKengetalStatuutDmfa(categorieKengetal, statuutDmfappl);
        } else {
            return new CategorieKengetalStatuutDmfappl(categorieKengetal, statuutDmfappl);
        }
    }

    public static CategorieKengetalStatuut create(RekenTijd rekenTijd, Rszppo rszppo) {
        DmfapplWnkengetal werknemersKengetal = rszppo.getWerknemersKengetal();
        WerkgeversCategorie werkgeversCategorie = rszppo.getWerkgeversCategorie();
        CategorieKengetal categorieKengetal = CategorieKengetalFactory.getCategorieKengetal(rekenTijd, werkgeversCategorie, werknemersKengetal);
        DmfapplStatuutDmfappl statuut = rszppo.getStatuutDmfappl();
        return getCategorieKengetalStatuut(rekenTijd, categorieKengetal, statuut);
    }
}
